UPDATE clinic_appointment
SET status = 'expired',
    update_by = #{updateBy},
    update_time = NOW()
WHERE status = 'pending'
  AND (
    appointment_date < #{today}
    OR (
      appointment_date = #{today}
      AND (
        CASE
          WHEN INSTR(appointment_time, '-') > 0
            THEN SUBSTRING_INDEX(appointment_time, '-', 1)
          ELSE appointment_time
        END
      ) <= #{currentTime}
    )
  )

mapper.select:
SELECT

FROM clinic_appointment
WHERE status = 'pending'
  AND (
    appointment_date < #{today}
    OR (
      appointment_date = #{today}
      AND (
        CASE
          WHEN INSTR(appointment_time, '-') > 0
            THEN SUBSTRING_INDEX(appointment_time, '-', 1)
          ELSE appointment_time
        END
      ) <= #{currentTime}
    )

      OR (
        create_time IS NOT NULL
        AND create_time <= DATE_SUB(NOW(), INTERVAL #{pendingTimeoutMinutes} MINUTE)
      )

  )
ORDER BY create_time ASC, appointment_id ASC
